import { z } from "zod";

export const sourcePlatformSchema = z.enum([
  "chatgpt",
  "claude",
  "gemini",
  "grok",
  "deepseek",
  "notebooklm",
  "unknown",
]);

export const roleSchema = z.enum([
  "system",
  "user",
  "assistant",
  "tool",
  "unknown",
]);

export const paragraphBlockSchema = z.object({
  type: z.literal("paragraph"),
  text: z.string(),
});

export const headingBlockSchema = z.object({
  type: z.literal("heading"),
  level: z.number().int().min(1).max(6),
  text: z.string(),
});

export const listBlockSchema = z.object({
  type: z.literal("list"),
  ordered: z.boolean(),
  items: z.array(z.string()),
});

export const codeBlockSchema = z.object({
  type: z.literal("code"),
  language: z.string().default("text"),
  text: z.string(),
});

export const quoteBlockSchema = z.object({
  type: z.literal("quote"),
  text: z.string(),
});

export const tableBlockSchema = z.object({
  type: z.literal("table"),
  headers: z.array(z.string()),
  rows: z.array(z.array(z.string())),
});

export const blockSchema = z.discriminatedUnion("type", [
  paragraphBlockSchema,
  headingBlockSchema,
  listBlockSchema,
  codeBlockSchema,
  quoteBlockSchema,
  tableBlockSchema,
]);

export const messageSchema = z.object({
  id: z.string(),
  role: roleSchema,
  blocks: z.array(blockSchema),
});

export const conversationSchema = z.object({
  id: z.string(),
  title: z.string(),
  source: z.object({
    url: z.string().url(),
    platform: sourcePlatformSchema,
  }),
  messages: z.array(messageSchema),
});

export type SourcePlatform = z.infer<typeof sourcePlatformSchema>;
export type Role = z.infer<typeof roleSchema>;
export type Block = z.infer<typeof blockSchema>;
export type Message = z.infer<typeof messageSchema>;
export type Conversation = z.infer<typeof conversationSchema>;

import { z } from "zod";

import { blockSchema, roleSchema } from "./conversation.js";

export const importSnapshotMetadataSchema = z.object({
  articleCount: z.number().int().nonnegative(),
  messageCount: z.number().int().nonnegative(),
  rawHtmlBytes: z.number().int().nonnegative(),
});

export const normalizedSnapshotStructuringSchema = z.object({
  status: z.enum(["disabled", "skipped", "applied", "partial", "failed"]),
  provider: z.string(),
  model: z.string().optional(),
  candidateCount: z.number().int().nonnegative(),
  attemptedCount: z.number().int().nonnegative(),
  repairedCount: z.number().int().nonnegative(),
  failedCount: z.number().int().nonnegative(),
  skippedCount: z.number().int().nonnegative(),
  skippedReason: z.string().optional(),
});

export const normalizedSnapshotParserSchema = z.object({
  source: z.string().optional(),
  blockCount: z.number().int().nonnegative().optional(),
  usedFallback: z.boolean().optional(),
  strategy: z.enum(["deterministic", "ai-repair", "fallback"]).optional(),
  model: z.string().optional(),
});

export const normalizedSnapshotMessageSchema = z.object({
  id: z.string(),
  role: roleSchema,
  blocks: z.array(blockSchema),
  rawText: z.string().optional(),
  rawHtml: z.string().optional(),
  parser: normalizedSnapshotParserSchema.optional(),
});

export const normalizedSnapshotPayloadSchema = z.object({
  title: z.string(),
  messages: z.array(normalizedSnapshotMessageSchema),
  warnings: z.array(z.string()),
  structuring: normalizedSnapshotStructuringSchema.optional(),
});

export const importSnapshotSchema = z.object({
  importId: z.string(),
  sourceUrl: z.string().url(),
  finalUrl: z.string().url(),
  fetchedAt: z.string(),
  pageTitle: z.string(),
  rawHtmlBytes: z.number().int().nonnegative(),
  rawHtmlPreview: z.string(),
  rawHtmlTruncated: z.boolean(),
  normalizedPayload: normalizedSnapshotPayloadSchema,
  fetchMetadata: importSnapshotMetadataSchema,
});

export type ImportSnapshot = z.infer<typeof importSnapshotSchema>;
export type ImportSnapshotMetadata = z.infer<
  typeof importSnapshotMetadataSchema
>;
export type NormalizedSnapshotMessage = z.infer<
  typeof normalizedSnapshotMessageSchema
>;
export type NormalizedSnapshotParser = z.infer<
  typeof normalizedSnapshotParserSchema
>;
export type NormalizedSnapshotPayload = z.infer<
  typeof normalizedSnapshotPayloadSchema
>;
export type NormalizedSnapshotStructuring = z.infer<
  typeof normalizedSnapshotStructuringSchema
>;

import { oc } from "@orpc/contract";
import { z } from "zod";

import {
  adjustmentMetricsSchema,
  adjustmentSessionDetailSchema,
  adjustmentTargetFormatSchema,
  appendAdjustmentMessageRequestSchema,
  createAdjustmentSessionRequestSchema,
  formatRuleSchema,
} from "./adjustments.js";
import {
  deleteMessageRequestSchema,
  deleteRoundRequestSchema,
  messageDeletionSchema,
  restoreMessageRequestSchema,
} from "./deletions.js";
import {
  importJobSchema,
  importListRequestSchema,
  importRequestSchema,
  importSummarySchema,
} from "./imports.js";
import { importSnapshotSchema } from "./snapshots.js";

export const contract = {
  imports: {
    list: oc
      .input(importListRequestSchema.optional())
      .output(z.array(importSummarySchema)),

    delete: oc
      .input(z.object({ id: z.string() }))
      .output(z.object({ deleted: z.boolean() })),

    create: oc.input(importRequestSchema).output(importJobSchema),

    get: oc.input(z.object({ id: z.string() })).output(importJobSchema),

    snapshot: oc
      .input(z.object({ id: z.string() }))
      .output(importSnapshotSchema),

    rawHtml: oc.input(z.object({ id: z.string() })).output(z.string()),

    exportArtifact: oc
      .input(
        z.object({
          id: z.string(),
          format: z.enum(["markdown", "handover", "json"]),
        }),
      )
      .output(z.string()),
  },

  adjustments: {
    listSessions: oc
      .input(
        z.object({
          importId: z.string(),
          format: adjustmentTargetFormatSchema.optional(),
        }),
      )
      .output(z.array(adjustmentSessionDetailSchema.shape.session)),

    createSession: oc
      .input(
        createAdjustmentSessionRequestSchema.extend({
          importId: z.string(),
        }),
      )
      .output(adjustmentSessionDetailSchema),

    getSession: oc
      .input(z.object({ id: z.string() }))
      .output(adjustmentSessionDetailSchema),

    appendMessage: oc
      .input(
        appendAdjustmentMessageRequestSchema.extend({
          sessionId: z.string(),
        }),
      )
      .output(adjustmentSessionDetailSchema),

    discard: oc
      .input(z.object({ sessionId: z.string() }))
      .output(adjustmentSessionDetailSchema),

    metrics: oc
      .input(
        z.object({
          importId: z.string(),
          format: adjustmentTargetFormatSchema,
        }),
      )
      .output(adjustmentMetricsSchema),
  },

  rules: {
    list: oc
      .input(
        z.object({
          importId: z.string(),
          format: adjustmentTargetFormatSchema.optional(),
        }),
      )
      .output(z.array(formatRuleSchema)),

    disable: oc
      .input(z.object({ id: z.string(), importId: z.string().optional() }))
      .output(formatRuleSchema),

    promote: oc.input(z.object({ id: z.string() })).output(formatRuleSchema),

    demote: oc
      .input(z.object({ id: z.string(), importId: z.string() }))
      .output(formatRuleSchema),
  },

  deletions: {
    list: oc
      .input(z.object({ importId: z.string() }))
      .output(z.array(messageDeletionSchema)),

    delete: oc.input(deleteMessageRequestSchema).output(messageDeletionSchema),

    deleteRound: oc
      .input(deleteRoundRequestSchema)
      .output(z.array(messageDeletionSchema)),

    restore: oc
      .input(restoreMessageRequestSchema)
      .output(z.object({ restored: z.boolean() })),
  },

  health: {
    check: oc.output(
      z.object({
        ok: z.boolean(),
        service: z.string(),
        databasePath: z.string(),
      }),
    ),
  },
};

