  1вҶ’import { contract, importSnapshotSchema } from "@chat-exporter/shared";
  2вҶ’import { implement, ORPCError } from "@orpc/server";
  3вҶ’
  4вҶ’import { databasePath, withTransaction } from "../db/client.js";
  5вҶ’import {
  6вҶ’  AgentUnavailableError,
  7вҶ’  runAgentTurn,
  8вҶ’} from "../lib/adjustment-agent.js";
  9вҶ’import {
 10вҶ’  appendAdjustmentMessage,
 11вҶ’  createAdjustmentSession,
 12вҶ’  createFormatRuleDirect,
 13вҶ’  demoteRuleToLocal,
 14вҶ’  disableFormatRule,
 15вҶ’  discardAdjustmentSession,
 16вҶ’  getAdjustmentMetrics,
 17вҶ’  getAdjustmentSessionDetail,
 18вҶ’  listAdjustmentSessions,
 19вҶ’  listFormatRules,
 20вҶ’  markSessionApplied,
 21вҶ’  promoteRuleToProfile,
 22вҶ’  recordAdjustmentEvent,
 23вҶ’  reopenAdjustmentSession,
 24вҶ’  updateFormatRuleEffect,
 25вҶ’} from "../lib/adjustment-repository.js";
 26вҶ’import {
 27вҶ’  listDeletions,
 28вҶ’  restoreMessage,
 29вҶ’  softDeleteMessage,
 30вҶ’  softDeleteRound,
 31вҶ’} from "../lib/delete-repository.js";
 32вҶ’import { getPersistedImportSnapshot } from "../lib/import-repository.js";
 33вҶ’import {
 34вҶ’  createImportJob,
 35вҶ’  deleteImportJob,
 36вҶ’  getImportJob,
 37вҶ’  listImportJobs,
 38вҶ’  runImportJob,
 39вҶ’} from "../lib/import-store.js";
 40вҶ’
 41вҶ’export const RAW_HTML_PREVIEW_LENGTH = 16_000;
 42вҶ’
 43вҶ’function isSupportedChatGptShareLink(urlString: string) {
 44вҶ’  let url: URL;
 45вҶ’  try {
 46вҶ’    url = new URL(urlString);
 47вҶ’  } catch {
 48вҶ’    return false;
 49вҶ’  }
 50вҶ’  return url.hostname === "chatgpt.com" && url.pathname.startsWith("/share/");
 51вҶ’}
 52вҶ’
 53вҶ’const os = implement(contract);
 54вҶ’
 55вҶ’export const router = os.router({
 56вҶ’  imports: {
 57вҶ’    list: os.imports.list.handler(({ input }) => {
 58вҶ’      return listImportJobs(input);
 59вҶ’    }),
 60вҶ’
 61вҶ’    delete: os.imports.delete.handler(({ input }) => {
 62вҶ’      const job = getImportJob(input.id);
 63вҶ’      if (!job) {
 64вҶ’        throw new ORPCError("NOT_FOUND", {
 65вҶ’          message: "Import nicht gefunden.",
 66вҶ’        });
 67вҶ’      }
 68вҶ’      const deleted = deleteImportJob(input.id);
 69вҶ’      return { deleted };
 70вҶ’    }),
 71вҶ’
 72вҶ’    create: os.imports.create.handler(({ input }) => {
 73вҶ’      if (!isSupportedChatGptShareLink(input.url)) {
 74вҶ’        throw new ORPCError("BAD_REQUEST", {
 75вҶ’          message:
 76вҶ’            "Dieser erste Stand akzeptiert nur Г¶ffentliche ChatGPT-Share-Links.",
 77вҶ’        });
 78вҶ’      }
 79вҶ’
 80вҶ’      const job = createImportJob(input);
 81вҶ’      void runImportJob(job.id);
 82вҶ’      return job;
 83вҶ’    }),
 84вҶ’
 85вҶ’    get: os.imports.get.handler(({ input }) => {
 86вҶ’      const job = getImportJob(input.id);
 87вҶ’
 88вҶ’      if (!job) {
 89вҶ’        throw new ORPCError("NOT_FOUND", {
 90вҶ’          message: "Import nicht gefunden.",
 91вҶ’        });
 92вҶ’      }
 93вҶ’
 94вҶ’      return job;
 95вҶ’    }),
 96вҶ’
 97вҶ’    snapshot: os.imports.snapshot.handler(({ input }) => {
 98вҶ’      const snapshot = getPersistedImportSnapshot(input.id);
 99вҶ’
100вҶ’      if (!snapshot) {
101вҶ’        throw new ORPCError("NOT_FOUND", {
102вҶ’          message: "Import-Snapshot nicht gefunden.",
103вҶ’        });
104вҶ’      }
105вҶ’
106вҶ’      const rawHtmlPreview = snapshot.rawHtml.slice(0, RAW_HTML_PREVIEW_LENGTH);
107вҶ’
108вҶ’      return importSnapshotSchema.parse({
109вҶ’        importId: snapshot.importId,
110вҶ’        sourceUrl: snapshot.sourceUrl,
111вҶ’        finalUrl: snapshot.finalUrl,
112вҶ’        fetchedAt: snapshot.fetchedAt,
113вҶ’        pageTitle: snapshot.pageTitle,
114вҶ’        rawHtmlBytes: Buffer.byteLength(snapshot.rawHtml, "utf8"),
115вҶ’        rawHtmlPreview,
116вҶ’        rawHtmlTruncated: snapshot.rawHtml.length > rawHtmlPreview.length,
117вҶ’        normalizedPayload: snapshot.normalizedPayload,
118вҶ’        fetchMetadata: snapshot.fetchMetadata,
119вҶ’      });
120вҶ’    }),
121вҶ’
122вҶ’    rawHtml: os.imports.rawHtml.handler(({ input }) => {
123вҶ’      const snapshot = getPersistedImportSnapshot(input.id);
124вҶ’
125вҶ’      if (!snapshot) {
126вҶ’        throw new ORPCError("NOT_FOUND", {
127вҶ’          message: "Import-Snapshot nicht gefunden.",
128вҶ’        });
129вҶ’      }
130вҶ’
131вҶ’      return snapshot.rawHtml;
132вҶ’    }),
133вҶ’
134вҶ’    // Design-Entscheidung: Dieser Endpoint liefert absichtlich rohe, unverГӨnderte
135вҶ’    // Artefakte ohne angewendete Format-Rules. Client-seitiger Markdown-Download
136вҶ’    // verwendet stattdessen `displayedMarkdown` (mit `applyMarkdownRules` inkl.
137вҶ’    // format_profile-Rules). Г„nderungen hier dГјrfen diese Trennung nicht aufheben.
138вҶ’    exportArtifact: os.imports.exportArtifact.handler(({ input }) => {
139вҶ’      const job = getImportJob(input.id);
140вҶ’
141вҶ’      if (!job || !job.artifacts) {
142вҶ’        throw new ORPCError("NOT_FOUND", {
143вҶ’          message: "Export-Artefakt nicht gefunden.",
144вҶ’        });
145вҶ’      }
146вҶ’
147вҶ’      switch (input.format) {
148вҶ’        case "markdown":
149вҶ’          return job.artifacts.markdown;
150вҶ’        case "handover":
151вҶ’          return job.artifacts.handover;
152вҶ’        case "json":
153вҶ’          return job.artifacts.json;
154вҶ’        default:
155вҶ’          throw new ORPCError("BAD_REQUEST", {
156вҶ’            message: "Nicht unterstГјtztes Exportformat.",
157вҶ’          });
158вҶ’      }
159вҶ’    }),
160вҶ’  },
161вҶ’
162вҶ’  adjustments: {
163вҶ’    listSessions: os.adjustments.listSessions.handler(({ input }) => {
164вҶ’      const job = getImportJob(input.importId);
165вҶ’
166вҶ’      if (!job) {
167вҶ’        throw new ORPCError("NOT_FOUND", {
168вҶ’          message: "Import nicht gefunden.",
169вҶ’        });
170вҶ’      }
171вҶ’
172вҶ’      return listAdjustmentSessions(input.importId, input.format);
173вҶ’    }),
174вҶ’
175вҶ’    createSession: os.adjustments.createSession.handler(({ input }) => {
176вҶ’      const job = getImportJob(input.importId);
177вҶ’
178вҶ’      if (!job) {
179вҶ’        throw new ORPCError("NOT_FOUND", {
180вҶ’          message: "Import nicht gefunden.",
181вҶ’        });
182вҶ’      }
183вҶ’
184вҶ’      const { session } = createAdjustmentSession({
185вҶ’        importId: input.importId,
186вҶ’        selection: input.selection,
187вҶ’        targetFormat: input.targetFormat,
188вҶ’      });
189вҶ’      const detail = getAdjustmentSessionDetail(session.id);
190вҶ’
191вҶ’      if (!detail) {
192вҶ’        throw new ORPCError("INTERNAL_SERVER_ERROR", {
193вҶ’          message: "Anpassungssession konnte nicht geladen werden.",
194вҶ’        });
195вҶ’      }
196вҶ’
197вҶ’      return detail;
198вҶ’    }),
199вҶ’
200вҶ’    getSession: os.adjustments.getSession.handler(({ input }) => {
201вҶ’      const detail = getAdjustmentSessionDetail(input.id);
202вҶ’
203вҶ’      if (!detail) {
204вҶ’        throw new ORPCError("NOT_FOUND", {
205вҶ’          message: "Anpassungssession nicht gefunden.",
206вҶ’        });
207вҶ’      }
208вҶ’
209вҶ’      return detail;
210вҶ’    }),
211вҶ’
212вҶ’    appendMessage: os.adjustments.appendMessage.handler(async ({ input }) => {
213вҶ’      const detail = getAdjustmentSessionDetail(input.sessionId);
214вҶ’
215вҶ’      if (!detail) {
216вҶ’        throw new ORPCError("NOT_FOUND", {
217вҶ’          message: "Anpassungssession nicht gefunden.",
218вҶ’        });
219вҶ’      }
220вҶ’
221вҶ’      // Phase 1 вҖ” Transaction: reopen (if needed) + append user message + reload detail
222вҶ’      const latestDetail = withTransaction(() => {
223вҶ’        const freshDetail = getAdjustmentSessionDetail(input.sessionId);
224вҶ’
225вҶ’        if (!freshDetail) {
226вҶ’          throw new ORPCError("INTERNAL_SERVER_ERROR", {
227вҶ’            message: "Anpassungssession konnte nicht neu geladen werden.",
228вҶ’          });
229вҶ’        }
230вҶ’
231вҶ’        if (freshDetail.session.status === "applied") {
232вҶ’          reopenAdjustmentSession(input.sessionId);
233вҶ’        }
234вҶ’
235вҶ’        appendAdjustmentMessage(input.sessionId, "user", input.content);
236вҶ’
237вҶ’        const reloaded = getAdjustmentSessionDetail(input.sessionId);
238вҶ’
239вҶ’        if (!reloaded) {
240вҶ’          throw new ORPCError("INTERNAL_SERVER_ERROR", {
241вҶ’            message: "Anpassungssession konnte nicht neu geladen werden.",
242вҶ’          });
243вҶ’        }
244вҶ’
245вҶ’        return reloaded;
246вҶ’      });
247вҶ’
248вҶ’      const activeRules = listFormatRules(
249вҶ’        detail.session.importId,
250вҶ’        detail.session.targetFormat,
251вҶ’      ).filter((rule: { status: string }) => rule.status === "active");
252вҶ’
253вҶ’      // Phase 2 вҖ” no wrapper: async AI call
254вҶ’      try {
255вҶ’        const job = getImportJob(detail.session.importId);
256вҶ’        const result = await runAgentTurn({
257вҶ’          sessionDetail: latestDetail,
258вҶ’          activeRules,
259вҶ’          job,
260вҶ’          callbacks: {
261вҶ’            onCreateRule: async ({ selector, effect, description }) => {
262вҶ’              const rule = createFormatRuleDirect({
263вҶ’                importId: latestDetail.session.importId,
264вҶ’                targetFormat: latestDetail.session.targetFormat,
265вҶ’                selector,
266вҶ’                effect: {
267вҶ’                  type: "custom_style" as const,
268вҶ’                  ...effect,
269вҶ’                  description,
270вҶ’                },
271вҶ’                instruction: description,
272вҶ’                sourceSessionId: input.sessionId,
273вҶ’              });
274вҶ’              return { ruleId: rule.id };
275вҶ’            },
276вҶ’            onUpdateRule: async ({ ruleId, effect, description }) => {
277вҶ’              updateFormatRuleEffect(
278вҶ’                ruleId,
279вҶ’                { type: "custom_style" as const, ...effect, description },
280вҶ’                description,
281вҶ’              );
282вҶ’            },
283вҶ’            onDeleteRule: async (ruleId) => {
284вҶ’              disableFormatRule(ruleId, latestDetail.session.importId);
285вҶ’            },
286вҶ’          },
287вҶ’        });
288вҶ’
289вҶ’        // Phase 3 вҖ” persist assistant message + events
290вҶ’        withTransaction(() => {
291вҶ’          appendAdjustmentMessage(
292вҶ’            input.sessionId,
293вҶ’            "assistant",
294вҶ’            result.assistantMessage,
295вҶ’          );
296вҶ’
297вҶ’          for (const action of result.actions) {
298вҶ’            recordAdjustmentEvent({
