import { describe, expect, test } from "vitest";
import {
  conversationSnapshotSchema,
  messageEditSchema,
  saveMessageEditRequestSchema,
  deleteMessageEditRequestSchema,
  createSnapshotRequestSchema,
  activateSnapshotRequestSchema,
  renameSnapshotRequestSchema,
  resolvedMessageSchema,
} from "../edits.js";
import type {
  ConversationSnapshot,
  MessageEdit,
  SaveMessageEditRequest,
  DeleteMessageEditRequest,
  CreateSnapshotRequest,
  ActivateSnapshotRequest,
  RenameSnapshotRequest,
  ResolvedMessage,
} from "../edits.js";

// --- Fixtures ---

const validSnapshot = {
  id: "snap-1",
  importId: "imp-1",
  label: "Draft v1",
  isActive: true,
  createdAt: "2026-01-01T00:00:00Z",
  updatedAt: "2026-01-01T00:00:00Z",
};

const validMessageEdit = {
  id: "edit-1",
  importId: "imp-1",
  snapshotId: "snap-1",
  messageId: "msg-1",
  createdAt: "2026-01-01T00:00:00Z",
  updatedAt: "2026-01-01T00:00:00Z",
};

const validBlocks = [
  { type: "paragraph" as const, text: "Hello world" },
  { type: "heading" as const, level: 2, text: "Section" },
];

// --- conversationSnapshotSchema ---

describe("conversationSnapshotSchema", () => {
  test("accepts a valid snapshot", () => {
    const result = conversationSnapshotSchema.safeParse(validSnapshot);

    expect(result.success).toBe(true);
  });

  test("accepts snapshot with isActive false", () => {
    const result = conversationSnapshotSchema.safeParse({
      ...validSnapshot,
      isActive: false,
    });

    expect(result.success).toBe(true);
  });

  test.each([
    ["missing id", { ...validSnapshot, id: undefined }],
    ["missing importId", { ...validSnapshot, importId: undefined }],
    ["missing label", { ...validSnapshot, label: undefined }],
    ["missing isActive", { ...validSnapshot, isActive: undefined }],
    ["missing createdAt", { ...validSnapshot, createdAt: undefined }],
    ["missing updatedAt", { ...validSnapshot, updatedAt: undefined }],
    ["wrong type for isActive", { ...validSnapshot, isActive: "yes" }],
    ["wrong type for label", { ...validSnapshot, label: 123 }],
  ])("rejects invalid snapshot: %s", (_label, payload) => {
    const result = conversationSnapshotSchema.safeParse(payload);

    expect(result.success).toBe(false);
  });
});

// --- messageEditSchema ---

describe("messageEditSchema", () => {
  test("accepts a valid message edit without annotation", () => {
    const result = messageEditSchema.safeParse(validMessageEdit);

    expect(result.success).toBe(true);
  });

  test("accepts a valid message edit with annotation", () => {
    const result = messageEditSchema.safeParse({
      ...validMessageEdit,
      annotation: "Fixed typo",
    });

    expect(result.success).toBe(true);
    if (result.success) {
      expect(result.data.annotation).toBe("Fixed typo");
    }
  });

  test.each([
    ["missing id", { ...validMessageEdit, id: undefined }],
    ["missing importId", { ...validMessageEdit, importId: undefined }],
    ["missing snapshotId", { ...validMessageEdit, snapshotId: undefined }],
    ["missing messageId", { ...validMessageEdit, messageId: undefined }],
    ["missing createdAt", { ...validMessageEdit, createdAt: undefined }],
    ["wrong type for annotation", { ...validMessageEdit, annotation: 42 }],
  ])("rejects invalid message edit: %s", (_label, payload) => {
    const result = messageEditSchema.safeParse(payload);

    expect(result.success).toBe(false);
  });
});

// --- saveMessageEditRequestSchema ---

describe("saveMessageEditRequestSchema", () => {
  const validRequest = {
    importId: "imp-1",
    snapshotId: "snap-1",
    messageId: "msg-1",
    editedBlocks: validBlocks,
  };

  test("accepts valid request without annotation", () => {
    const result = saveMessageEditRequestSchema.safeParse(validRequest);

    expect(result.success).toBe(true);
  });

  test("accepts valid request with annotation", () => {
    const result = saveMessageEditRequestSchema.safeParse({
      ...validRequest,
      annotation: "Improved clarity",
    });

    expect(result.success).toBe(true);
  });

  test("accepts request with various block types", () => {
    const result = saveMessageEditRequestSchema.safeParse({
      ...validRequest,
      editedBlocks: [
        { type: "paragraph", text: "intro" },
        { type: "code", language: "ts", text: "const x = 1" },
        { type: "list", ordered: true, items: ["a", "b"] },
        { type: "quote", text: "wise words" },
        { type: "table", headers: ["A"], rows: [["1"]] },
      ],
    });

    expect(result.success).toBe(true);
  });

  test.each([
    ["missing importId", { ...validRequest, importId: undefined }],
    ["missing snapshotId", { ...validRequest, snapshotId: undefined }],
    ["missing messageId", { ...validRequest, messageId: undefined }],
    ["missing editedBlocks", { ...validRequest, editedBlocks: undefined }],
    ["empty editedBlocks is allowed", { ...validRequest, editedBlocks: [] }],
    [
      "invalid block type",
      {
        ...validRequest,
        editedBlocks: [{ type: "unknown", text: "x" }],
      },
    ],
  ])("handles edge case: %s", (_label, payload) => {
    const result = saveMessageEditRequestSchema.safeParse(payload);

    if (_label === "empty editedBlocks is allowed") {
      expect(result.success).toBe(true);
    } else {
      expect(result.success).toBe(false);
    }
  });
});

// --- deleteMessageEditRequestSchema ---

describe("deleteMessageEditRequestSchema", () => {
  test("accepts valid request", () => {
    const result = deleteMessageEditRequestSchema.safeParse({
      importId: "imp-1",
      snapshotId: "snap-1",
      messageId: "msg-1",
    });

    expect(result.success).toBe(true);
  });

  test.each([
    ["missing importId", { snapshotId: "s", messageId: "m" }],
    ["missing snapshotId", { importId: "i", messageId: "m" }],
    ["missing messageId", { importId: "i", snapshotId: "s" }],
  ])("rejects invalid request: %s", (_label, payload) => {
    const result = deleteMessageEditRequestSchema.safeParse(payload);

    expect(result.success).toBe(false);
  });
});

// --- createSnapshotRequestSchema ---

describe("createSnapshotRequestSchema", () => {
  test("accepts valid request", () => {
    const result = createSnapshotRequestSchema.safeParse({
      importId: "imp-1",
      label: "My Snapshot",
    });

    expect(result.success).toBe(true);
  });

  test.each([
    ["missing importId", { label: "x" }],
    ["missing label", { importId: "i" }],
    ["wrong type for label", { importId: "i", label: 42 }],
  ])("rejects invalid request: %s", (_label, payload) => {
    const result = createSnapshotRequestSchema.safeParse(payload);

    expect(result.success).toBe(false);
  });
});

// --- activateSnapshotRequestSchema ---

describe("activateSnapshotRequestSchema", () => {
  test("accepts valid request", () => {
    const result = activateSnapshotRequestSchema.safeParse({
      snapshotId: "snap-1",
    });

    expect(result.success).toBe(true);
  });

  test("rejects missing snapshotId", () => {
    const result = activateSnapshotRequestSchema.safeParse({});

    expect(result.success).toBe(false);
  });
});

// --- renameSnapshotRequestSchema ---

describe("renameSnapshotRequestSchema", () => {
  test("accepts valid request", () => {
    const result = renameSnapshotRequestSchema.safeParse({
      snapshotId: "snap-1",
      label: "New name",
    });

    expect(result.success).toBe(true);
  });

  test.each([
    ["missing snapshotId", { label: "x" }],
    ["missing label", { snapshotId: "s" }],
  ])("rejects invalid request: %s", (_label, payload) => {
    const result = renameSnapshotRequestSchema.safeParse(payload);

    expect(result.success).toBe(false);
  });
});

// --- resolvedMessageSchema ---

describe("resolvedMessageSchema", () => {
  test("accepts valid resolved message", () => {
    const result = resolvedMessageSchema.safeParse({
      messageId: "msg-1",
      blocks: validBlocks,
      isEdited: true,
    });

    expect(result.success).toBe(true);
  });

  test("accepts unedited resolved message", () => {
    const result = resolvedMessageSchema.safeParse({
      messageId: "msg-1",
      blocks: [],
      isEdited: false,
    });

    expect(result.success).toBe(true);
  });

  test.each([
    ["missing messageId", { blocks: [], isEdited: false }],
    ["missing blocks", { messageId: "m", isEdited: false }],
    ["missing isEdited", { messageId: "m", blocks: [] }],
    ["wrong type for isEdited", { messageId: "m", blocks: [], isEdited: "no" }],
  ])("rejects invalid resolved message: %s", (_label, payload) => {
    const result = resolvedMessageSchema.safeParse(payload);

    expect(result.success).toBe(false);
  });
});

// --- Type inference smoke tests ---

describe("type inference", () => {
  test("inferred types are assignable", () => {
    const snapshot: ConversationSnapshot = {
      id: "s",
      importId: "i",
      label: "l",
      isActive: true,
      createdAt: "c",
      updatedAt: "u",
    };

    const edit: MessageEdit = {
      id: "e",
      importId: "i",
      snapshotId: "s",
      messageId: "m",
      createdAt: "c",
      updatedAt: "u",
    };

    const saveReq: SaveMessageEditRequest = {
      importId: "i",
      snapshotId: "s",
      messageId: "m",
      editedBlocks: [{ type: "paragraph", text: "t" }],
    };

    const deleteReq: DeleteMessageEditRequest = {
      importId: "i",
      snapshotId: "s",
      messageId: "m",
    };

    const createReq: CreateSnapshotRequest = {
      importId: "i",
      label: "l",
    };

    const activateReq: ActivateSnapshotRequest = { snapshotId: "s" };

    const renameReq: RenameSnapshotRequest = { snapshotId: "s", label: "l" };

    const resolved: ResolvedMessage = {
      messageId: "m",
      blocks: [],
      isEdited: false,
    };

    // All variables should be defined (type check passes if code compiles)
    expect(snapshot).toBeDefined();
    expect(edit).toBeDefined();
    expect(saveReq).toBeDefined();
    expect(deleteReq).toBeDefined();
    expect(createReq).toBeDefined();
    expect(activateReq).toBeDefined();
    expect(renameReq).toBeDefined();
    expect(resolved).toBeDefined();
  });
});

import { describe, expect, test } from "vitest";

import { rawDb } from "./client.js";
import {
  conversationSnapshots,
  messageEdits,
} from "./schema.js";

describe("conversationSnapshots table", () => {
  test("table exists in database with correct columns", () => {
    const columns = rawDb
      .prepare("SELECT name, type, [notnull], dflt_value, pk FROM pragma_table_info('conversation_snapshots')")
      .all() as Array<{ name: string; type: string; notnull: number; dflt_value: string | null; pk: number }>;

    const columnMap = new Map(columns.map((c) => [c.name, c]));

    expect(columnMap.get("id")).toMatchObject({ type: "TEXT", pk: 1 });
    expect(columnMap.get("import_id")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("label")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("is_active")).toMatchObject({ type: "INTEGER", notnull: 1, dflt_value: "0" });
    expect(columnMap.get("created_at")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("updated_at")).toMatchObject({ type: "TEXT", notnull: 1 });
  });

  test("has index on import_id", () => {
    const indexes = rawDb
      .prepare("SELECT name FROM sqlite_master WHERE type = 'index' AND tbl_name = 'conversation_snapshots'")
      .all() as Array<{ name: string }>;

    const indexNames = indexes.map((i) => i.name);
    expect(indexNames).toContain("idx_conversation_snapshots_import_id");
  });

  test("foreign key references imports(id) with CASCADE delete", () => {
    const fks = rawDb
      .prepare("PRAGMA foreign_key_list('conversation_snapshots')")
      .all() as Array<{ table: string; from: string; to: string; on_delete: string }>;

    const importFk = fks.find((fk) => fk.from === "import_id");
    expect(importFk).toBeDefined();
    expect(importFk?.table).toBe("imports");
    expect(importFk?.to).toBe("id");
    expect(importFk?.on_delete).toBe("CASCADE");
  });

  test("Drizzle schema exports conversationSnapshots table", () => {
    expect(conversationSnapshots).toBeDefined();
    // Verify the table name in the Drizzle schema
    expect((conversationSnapshots as any)[Symbol.for("drizzle:Name")]).toBe("conversation_snapshots");
  });

  test("can insert and query a row via raw SQL", () => {
    const now = new Date().toISOString();
    const importId = `_test_cs_${Date.now()}`;
    const snapshotId = `_test_snap_${Date.now()}`;

    // Create a temporary import for FK
    rawDb.prepare("INSERT INTO imports (id, source_url, source_platform, mode, status, current_stage, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)").run(
      importId, "https://test.com", "test", "full", "completed", "done", now, now,
    );

    try {
      rawDb.prepare("INSERT INTO conversation_snapshots (id, import_id, label, is_active, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)").run(
        snapshotId, importId, "Test Snapshot", 0, now, now,
      );

      const row = rawDb.prepare("SELECT * FROM conversation_snapshots WHERE id = ?").get(snapshotId) as any;
      expect(row.label).toBe("Test Snapshot");
      expect(row.is_active).toBe(0);
    } finally {
      rawDb.prepare("DELETE FROM imports WHERE id = ?").run(importId);
    }
  });
});

describe("messageEdits table", () => {
  test("table exists in database with correct columns", () => {
    const columns = rawDb
      .prepare("SELECT name, type, [notnull], dflt_value, pk FROM pragma_table_info('message_edits')")
      .all() as Array<{ name: string; type: string; notnull: number; dflt_value: string | null; pk: number }>;

    const columnMap = new Map(columns.map((c) => [c.name, c]));

    expect(columnMap.get("id")).toMatchObject({ type: "TEXT", pk: 1 });
    expect(columnMap.get("import_id")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("snapshot_id")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("message_id")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("edited_blocks_json")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("annotation")).toMatchObject({ type: "TEXT", notnull: 0 });
    expect(columnMap.get("created_at")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("updated_at")).toMatchObject({ type: "TEXT", notnull: 1 });
  });

  test("has unique index on (snapshot_id, message_id)", () => {
    const indexes = rawDb
      .prepare("SELECT name, [unique] FROM sqlite_master WHERE type = 'index' AND tbl_name = 'message_edits'")
      .all() as Array<{ name: string; unique: number }>;

    const uniqueIdx = indexes.find((i) => i.name === "idx_message_edits_snapshot_message");
    expect(uniqueIdx).toBeDefined();
  });

  test("foreign key references imports(id) and conversation_snapshots(id) with CASCADE", () => {
    const fks = rawDb
      .prepare("PRAGMA foreign_key_list('message_edits')")
      .all() as Array<{ table: string; from: string; to: string; on_delete: string }>;

    const importFk = fks.find((fk) => fk.from === "import_id");
    expect(importFk).toBeDefined();
    expect(importFk?.table).toBe("imports");
    expect(importFk?.on_delete).toBe("CASCADE");

    const snapshotFk = fks.find((fk) => fk.from === "snapshot_id");
    expect(snapshotFk).toBeDefined();
    expect(snapshotFk?.table).toBe("conversation_snapshots");
    expect(snapshotFk?.on_delete).toBe("CASCADE");
  });

  test("Drizzle schema exports messageEdits table", () => {
    expect(messageEdits).toBeDefined();
    expect((messageEdits as any)[Symbol.for("drizzle:Name")]).toBe("message_edits");
  });

  test("enforces unique constraint on (snapshot_id, message_id)", () => {
    const now = new Date().toISOString();
    const importId = `_test_me_${Date.now()}`;
    const snapshotId = `_test_snap_me_${Date.now()}`;
    const messageId = "msg-1";

    rawDb.prepare("INSERT INTO imports (id, source_url, source_platform, mode, status, current_stage, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)").run(
      importId, "https://test.com", "test", "full", "completed", "done", now, now,
    );
    rawDb.prepare("INSERT INTO conversation_snapshots (id, import_id, label, is_active, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)").run(
      snapshotId, importId, "Test", 0, now, now,
    );

    try {
      rawDb.prepare("INSERT INTO message_edits (id, import_id, snapshot_id, message_id, edited_blocks_json, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?)").run(
        `edit-1-${Date.now()}`, importId, snapshotId, messageId, "[]", now, now,
      );

      // Duplicate (snapshot_id, message_id) should fail
      expect(() =>
        rawDb.prepare("INSERT INTO message_edits (id, import_id, snapshot_id, message_id, edited_blocks_json, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?)").run(
          `edit-2-${Date.now()}`, importId, snapshotId, messageId, "[]", now, now,
        ),
      ).toThrow();
    } finally {
      rawDb.prepare("DELETE FROM imports WHERE id = ?").run(importId);
    }
  });
});

describe("type exports", () => {
  test("ConversationSnapshotRecord type is exported", async () => {
    const schemaModule = await import("./schema.js");
    // Type exports don't exist at runtime, but we can check the table $inferSelect
    expect(conversationSnapshots.$inferSelect).toBeDefined;
    expect(messageEdits.$inferSelect).toBeDefined;
    // Verify exports exist in module
    expect(schemaModule.conversationSnapshots).toBeDefined();
    expect(schemaModule.messageEdits).toBeDefined();
  });
});

import { defineConfig } from "vitest/config";

export default defineConfig({
  test: {
    globals: true,
    include: ["src/**/*.test.ts"],
  },
});

