  1вҶ’import type { MessageDeletion } from "@chat-exporter/shared";
  2вҶ’import { and, eq } from "drizzle-orm";
  3вҶ’import { db, withTransaction } from "../db/client.js";
  4вҶ’import { imports, messageDeletions } from "../db/schema.js";
  5вҶ’
  6вҶ’export function listDeletions(importId: string): MessageDeletion[] {
  7вҶ’  const rows = db
  8вҶ’    .select()
  9вҶ’    .from(messageDeletions)
 10вҶ’    .where(eq(messageDeletions.importId, importId))
 11вҶ’    .all();
 12вҶ’
 13вҶ’  return rows.map((r) => ({
 14вҶ’    id: r.id,
 15вҶ’    importId: r.importId,
 16вҶ’    messageId: r.messageId,
 17вҶ’    reason: r.reason ?? undefined,
 18вҶ’    deletedAt: r.deletedAt,
 19вҶ’  }));
 20вҶ’}
 21вҶ’
 22вҶ’export function softDeleteMessage(
 23вҶ’  importId: string,
 24вҶ’  messageId: string,
 25вҶ’  reason?: string,
 26вҶ’): MessageDeletion {
 27вҶ’  const id = crypto.randomUUID();
 28вҶ’  const deletedAt = new Date().toISOString();
 29вҶ’
 30вҶ’  db.insert(messageDeletions)
 31вҶ’    .values({ id, importId, messageId, reason: reason ?? null, deletedAt })
 32вҶ’    .run();
 33вҶ’
 34вҶ’  return { id, importId, messageId, reason, deletedAt };
 35вҶ’}
 36вҶ’
 37вҶ’export function softDeleteRound(
 38вҶ’  importId: string,
 39вҶ’  userMessageId: string,
 40вҶ’  reason?: string,
 41вҶ’): MessageDeletion[] {
 42вҶ’  const row = db
 43вҶ’    .select({ conversationJson: imports.conversationJson })
 44вҶ’    .from(imports)
 45вҶ’    .where(eq(imports.id, importId))
 46вҶ’    .get();
 47вҶ’
 48вҶ’  if (!row?.conversationJson) {
 49вҶ’    throw new Error("Import oder Conversation nicht gefunden.");
 50вҶ’  }
 51вҶ’
 52вҶ’  const conversation = JSON.parse(row.conversationJson);
 53вҶ’  const messages: Array<{ id: string; role: string }> = conversation.messages;
 54вҶ’
 55вҶ’  const userIdx = messages.findIndex((m) => m.id === userMessageId);
 56вҶ’  if (userIdx === -1) {
 57вҶ’    throw new Error("User-Message nicht gefunden.");
 58вҶ’  }
 59вҶ’
 60вҶ’  // Collect user message + all following non-user messages (the "round")
 61вҶ’  const roundMessageIds = [userMessageId];
 62вҶ’  for (let i = userIdx + 1; i < messages.length; i++) {
 63вҶ’    const msg = messages[i];
 64вҶ’    if (!msg || msg.role === "user") break;
 65вҶ’    roundMessageIds.push(msg.id);
 66вҶ’  }
 67вҶ’
 68вҶ’  return withTransaction(() => {
 69вҶ’    const deletions: MessageDeletion[] = [];
 70вҶ’    for (const msgId of roundMessageIds) {
 71вҶ’      // Skip if already deleted (unique constraint)
 72вҶ’      const existing = db
 73вҶ’        .select()
 74вҶ’        .from(messageDeletions)
 75вҶ’        .where(
 76вҶ’          and(
 77вҶ’            eq(messageDeletions.importId, importId),
 78вҶ’            eq(messageDeletions.messageId, msgId),
 79вҶ’          ),
 80вҶ’        )
 81вҶ’        .get();
 82вҶ’
 83вҶ’      if (!existing) {
 84вҶ’        deletions.push(softDeleteMessage(importId, msgId, reason));
 85вҶ’      }
 86вҶ’    }
 87вҶ’    return deletions;
 88вҶ’  });
 89вҶ’}
 90вҶ’
 91вҶ’export function restoreMessage(importId: string, messageId: string): boolean {
 92вҶ’  const result = db
 93вҶ’    .delete(messageDeletions)
 94вҶ’    .where(
 95вҶ’      and(
 96вҶ’        eq(messageDeletions.importId, importId),
 97вҶ’        eq(messageDeletions.messageId, messageId),
 98вҶ’      ),
 99вҶ’    )
100вҶ’    .run();
101вҶ’
102вҶ’  return result.changes > 0;
103вҶ’}
104вҶ’
105вҶ’export function isMessageDeleted(importId: string, messageId: string): boolean {
106вҶ’  const row = db
107вҶ’    .select()
108вҶ’    .from(messageDeletions)
109вҶ’    .where(
110вҶ’      and(
111вҶ’        eq(messageDeletions.importId, importId),
112вҶ’        eq(messageDeletions.messageId, messageId),
113вҶ’      ),
114вҶ’    )
115вҶ’    .get();
116вҶ’
117вҶ’  return !!row;
118вҶ’}
