 63вҶ’      onError: (error) => {
 64вҶ’        if (state.activeSessionDetail?.session.status === "applied") {
 65вҶ’          dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view });
 66вҶ’        } else {
 67вҶ’          dispatch({
 68вҶ’            type: "SET_SESSION_ERROR",
 69вҶ’            error: extractErrorMessage(
 70вҶ’              error,
 71вҶ’              "Anpassungssession konnte nicht verworfen werden.",
 72вҶ’            ),
 73вҶ’          });
 74вҶ’        }
 75вҶ’      },
 76вҶ’    }),
 77вҶ’  );
 78вҶ’
 79вҶ’  // Derived values
 80вҶ’  const isAdjustableView = adjustableViews.has(view);
 81вҶ’  const isAdjustModeEnabled = state.adjustModeByView[view];
 82вҶ’  const activeSelection = state.selectionByView[view];
 83вҶ’
 84вҶ’  // Disable adjust mode when switching to a non-adjustable view
 85вҶ’  useEffect(() => {
 86вҶ’    if (!isAdjustableView && isAdjustModeEnabled)
 87вҶ’      dispatch({ type: "SET_ADJUST_MODE", view, enabled: false });
 88вҶ’  }, [isAdjustModeEnabled, isAdjustableView, view]);
 89вҶ’
 90вҶ’  // Debounced session creation on selection change
 91вҶ’  useEffect(() => {
 92вҶ’    const currentSelection = state.selectionByView[view];
 93вҶ’    const activeSelectionKey = state.sessionSelectionKeyByView[view];
 94вҶ’    if (!isAdjustModeEnabled || !isAdjustableView || !currentSelection) return;
 95вҶ’
 96вҶ’    const nextSelectionKey = JSON.stringify(currentSelection);
 97вҶ’    if (
 98вҶ’      activeSelectionKey === nextSelectionKey &&
 99вҶ’      state.activeSessionDetail?.session.importId === jobId
100вҶ’    )
101вҶ’      return;
102вҶ’
103вҶ’    if (debounceRef.current !== null) clearTimeout(debounceRef.current);
104вҶ’
105вҶ’    debounceRef.current = setTimeout(() => {
106вҶ’      dispatch({ type: "SET_SESSION_ERROR", error: null });
107вҶ’      createSession.mutate(
108вҶ’        { importId: jobId, selection: currentSelection, targetFormat: view },
109вҶ’        {
110вҶ’          onSuccess: (detail) => {
111вҶ’            dispatch({ type: "SET_ACTIVE_SESSION_DETAIL", detail });
112вҶ’            dispatch({
113вҶ’              type: "SET_SESSION_SELECTION_KEY",
114вҶ’              view,
115вҶ’              key: nextSelectionKey,
116вҶ’            });
117вҶ’          },
118вҶ’          onError: (error) => {
119вҶ’            dispatch({
120вҶ’              type: "SET_SESSION_ERROR",
121вҶ’              error: extractErrorMessage(
122вҶ’                error,
123вҶ’                "Anpassungssession konnte nicht erstellt werden.",
124вҶ’              ),
125вҶ’            });
126вҶ’          },
127вҶ’        },
128вҶ’      );
129вҶ’    }, 250);
130вҶ’
131вҶ’    return () => {
132вҶ’      if (debounceRef.current !== null) clearTimeout(debounceRef.current);
133вҶ’    };
134вҶ’  }, [
135вҶ’    state.selectionByView[view],
136вҶ’    state.sessionSelectionKeyByView[view],
137вҶ’    state.activeSessionDetail,
138вҶ’    createSession.mutate,
139вҶ’    isAdjustModeEnabled,
140вҶ’    isAdjustableView,
141вҶ’    jobId,
142вҶ’    view,
143вҶ’  ]);
144вҶ’
145вҶ’  const toggleAdjustMode = useCallback(() => {
146вҶ’    if (!isAdjustableView) return;
147вҶ’    const nextEnabled = !state.adjustModeByView[view];
148вҶ’    dispatch({ type: "SET_ADJUST_MODE", view, enabled: nextEnabled });
149вҶ’    dispatch({ type: "SET_GUIDE_DISMISSED", view, dismissed: false });
150вҶ’    if (!nextEnabled) dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view });
151вҶ’  }, [isAdjustableView, state.adjustModeByView, view]);
152вҶ’
153вҶ’  const handleSelectionChange = useCallback(
154вҶ’    (selection: AdjustmentSelection, anchor: ViewportAnchor) => {
155вҶ’      const container = sectionRef.current;
156вҶ’      const r = container?.getBoundingClientRect();
157вҶ’      const scrollTop = container?.scrollTop ?? 0;
158вҶ’      const adjusted = r
159вҶ’        ? {
160вҶ’            top: anchor.top - r.top + scrollTop,
161вҶ’            bottom: anchor.bottom - r.top + scrollTop,
162вҶ’            left: anchor.left - r.left,
163вҶ’            width: anchor.width,
164вҶ’            height: anchor.height,
165вҶ’          }
166вҶ’        : anchor;
167вҶ’      dispatch({
168вҶ’        type: "SELECTION_CHANGED",
169вҶ’        view,
170вҶ’        selection,
171вҶ’        anchor: adjusted,
172вҶ’      });
173вҶ’    },
174вҶ’    [view],
175вҶ’  );
176вҶ’
177вҶ’  // Stable refs for values used in callbacks вҖ” prevents useCallback from
178вҶ’  // getting new references when mutation objects or state change.
179вҶ’  const latestRef = useRef({
180вҶ’    activeSessionDetail: state.activeSessionDetail,
181вҶ’    draftMessageByView: state.draftMessageByView,
182вҶ’    appendMutate: appendMessage.mutate,
183вҶ’    discardMutate: discardSession.mutate,
184вҶ’  });
185вҶ’  latestRef.current = {
186вҶ’    activeSessionDetail: state.activeSessionDetail,
187вҶ’    draftMessageByView: state.draftMessageByView,
188вҶ’    appendMutate: appendMessage.mutate,
189вҶ’    discardMutate: discardSession.mutate,
190вҶ’  };
191вҶ’
192вҶ’  const handleSubmitMessage = useCallback(
193вҶ’    (event: FormEvent<HTMLFormElement>) => {
194вҶ’      event.preventDefault();
195вҶ’      const { activeSessionDetail, draftMessageByView, appendMutate } =
196вҶ’        latestRef.current;
197вҶ’      if (!activeSessionDetail) return;
198вҶ’      const content = draftMessageByView[view].trim();
199вҶ’      if (!content) return;
200вҶ’      dispatch({ type: "SET_SESSION_ERROR", error: null });
201вҶ’      appendMutate({
202вҶ’        sessionId: activeSessionDetail.session.id,
203вҶ’        content,
204вҶ’      });
205вҶ’    },
206вҶ’    [view],
207вҶ’  );
208вҶ’
209вҶ’  const handleDiscardSession = useCallback(() => {
210вҶ’    const { activeSessionDetail, discardMutate } = latestRef.current;
211вҶ’    if (!activeSessionDetail) {
212вҶ’      dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view });
213вҶ’      return;
214вҶ’    }
215вҶ’    dispatch({ type: "SET_SESSION_ERROR", error: null });
216вҶ’    discardMutate({ sessionId: activeSessionDetail.session.id });
217вҶ’  }, [view]);
218вҶ’
219вҶ’  const handleDraftMessageChange = useCallback(
220вҶ’    (value: string) => dispatch({ type: "SET_DRAFT_MESSAGE", view, value }),
221вҶ’    [view],
222вҶ’  );
223вҶ’
224вҶ’  const setReplyVisible = useCallback(
225вҶ’    (visible: boolean) =>
226вҶ’      dispatch({ type: "SET_REPLY_VISIBLE", view, visible }),
227вҶ’    [view],
228вҶ’  );
229вҶ’
230вҶ’  const setGuideDismissed = useCallback(
231вҶ’    (dismissed: boolean) =>
232вҶ’      dispatch({ type: "SET_GUIDE_DISMISSED", view, dismissed }),
233вҶ’    [view],
234вҶ’  );
235вҶ’
236вҶ’  const clearCurrentAdjustmentState = useCallback(
237вҶ’    (targetView: ViewMode) =>
238вҶ’      dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view: targetView }),
239вҶ’    [],
240вҶ’  );
241вҶ’
242вҶ’  return {
243вҶ’    sectionRef,
244вҶ’    adjustModeEnabled: isAdjustModeEnabled,
245вҶ’    activeSessionDetail: state.activeSessionDetail,
246вҶ’    activeSelection,
247вҶ’    activeAnchor: state.anchorByView[view],
248вҶ’    activeDraftMessage: state.draftMessageByView[view],
249вҶ’    activeSessionError: state.sessionError,
250вҶ’    activeSessionLoading: createSession.isPending,
251вҶ’    isSubmitting: appendMessage.isPending,
252вҶ’    isDiscarding: discardSession.isPending,
253вҶ’    showGuide:
254вҶ’      isAdjustModeEnabled &&
255вҶ’      !activeSelection &&
256вҶ’      !state.guideDismissedByView[view],
257вҶ’    replyVisible: state.replyVisibleByView[view],
258вҶ’    guideDismissed: state.guideDismissedByView[view],
259вҶ’    toggleAdjustMode,
260вҶ’    handleSelectionChange,
261вҶ’    handleDraftMessageChange,
262вҶ’    handleSubmitMessage,
263вҶ’    handleDiscardSession,
264вҶ’    clearCurrentAdjustmentState,
265вҶ’    setReplyVisible,
266вҶ’    setGuideDismissed,
267вҶ’  };
268вҶ’}
