 1вҶ’import { useQuery, useQueryClient } from "@tanstack/react-query";
 2вҶ’import { useCallback, useMemo, useState } from "react";
 3вҶ’import { orpc } from "@/lib/orpc";
 4вҶ’import { rpc } from "@/lib/rpc";
 5вҶ’
 6вҶ’export function useMessageDeletion(importId: string) {
 7вҶ’  const queryClient = useQueryClient();
 8вҶ’  const [showDeleted, setShowDeleted] = useState(false);
 9вҶ’
10вҶ’  const deletionsQuery = useQuery({
11вҶ’    ...orpc.deletions.list.queryOptions({ input: { importId } }),
12вҶ’  });
13вҶ’
14вҶ’  const deletedMessageIds = useMemo(
15вҶ’    () => new Set(deletionsQuery.data?.map((d) => d.messageId)),
16вҶ’    [deletionsQuery.data],
17вҶ’  );
18вҶ’
19вҶ’  const invalidate = useCallback(() => {
20вҶ’    queryClient.invalidateQueries({ queryKey: orpc.deletions.list.key() });
21вҶ’  }, [queryClient]);
22вҶ’
23вҶ’  const deleteMessage = useCallback(
24вҶ’    async (messageId: string, reason?: string) => {
25вҶ’      const result = await rpc.deletions.delete({
26вҶ’        importId,
27вҶ’        messageId,
28вҶ’        reason,
29вҶ’      });
30вҶ’      invalidate();
31вҶ’      return result;
32вҶ’    },
33вҶ’    [importId, invalidate],
34вҶ’  );
35вҶ’
36вҶ’  const deleteRound = useCallback(
37вҶ’    async (messageId: string, reason?: string) => {
38вҶ’      const result = await rpc.deletions.deleteRound({
39вҶ’        importId,
40вҶ’        messageId,
41вҶ’        reason,
42вҶ’      });
43вҶ’      invalidate();
44вҶ’      return result;
45вҶ’    },
46вҶ’    [importId, invalidate],
47вҶ’  );
48вҶ’
49вҶ’  const restoreMessage = useCallback(
50вҶ’    async (messageId: string) => {
51вҶ’      const result = await rpc.deletions.restore({ importId, messageId });
52вҶ’      invalidate();
53вҶ’      return result;
54вҶ’    },
55вҶ’    [importId, invalidate],
56вҶ’  );
57вҶ’
58вҶ’  return {
59вҶ’    deletedMessageIds,
60вҶ’    deletionsCount: deletedMessageIds.size,
61вҶ’    isLoading: deletionsQuery.isLoading,
62вҶ’    showDeleted,
63вҶ’    setShowDeleted,
64вҶ’    deleteMessage,
65вҶ’    deleteRound,
66вҶ’    restoreMessage,
67вҶ’  };
68вҶ’}
