 61вҶ’function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
 62вҶ’  if (!job.artifacts) {
 63вҶ’    return "Artefakt ist noch nicht verfГјgbar.";
 64вҶ’  }
 65вҶ’
 66вҶ’  switch (view) {
 67вҶ’    case "markdown":
 68вҶ’      return job.artifacts.markdown;
 69вҶ’    case "handover":
 70вҶ’      return job.artifacts.handover;
 71вҶ’    case "json":
 72вҶ’      return job.artifacts.json;
 73вҶ’  }
 74вҶ’}
 75вҶ’
 76вҶ’export function FormatWorkspace({
 77вҶ’  activeStage,
 78вҶ’  elapsedTime,
 79вҶ’  job,
 80вҶ’  view,
 81вҶ’  onViewChange,
 82вҶ’}: FormatWorkspaceProps) {
 83вҶ’  const isAdjustableView = adjustableViews.has(view);
 84вҶ’
 85вҶ’  const session = useAdjustmentSession(view, job.id);
 86вҶ’  const rules = useFormatRules(view, job.id);
 87вҶ’  const deletion = useMessageDeletion(job.id);
 88вҶ’  const deletionToast = useDeletionToast();
 89вҶ’  const [deleteDialog, setDeleteDialog] = useState<{
 90вҶ’    messageId: string;
 91вҶ’    isRound: boolean;
 92вҶ’    preview: string;
 93вҶ’  } | null>(null);
 94вҶ’  const popover = useAdjustmentPopover();
 95вҶ’
 96вҶ’  const handleDeleteMessage = useCallback(
 97вҶ’    (messageId: string) => {
 98вҶ’      const msg = job.conversation?.messages.find((m) => m.id === messageId);
 99вҶ’      const preview =
100вҶ’        msg?.blocks
101вҶ’          .map((b) => ("text" in b ? b.text : b.type))
102вҶ’          .join(" ")
103вҶ’          .slice(0, 200) ?? messageId;
104вҶ’      setDeleteDialog({ messageId, isRound: false, preview });
105вҶ’    },
106вҶ’    [job.conversation?.messages],
107вҶ’  );
108вҶ’
109вҶ’  const handleDeleteRound = useCallback(
110вҶ’    (messageId: string) => {
111вҶ’      const msg = job.conversation?.messages.find((m) => m.id === messageId);
112вҶ’      const preview =
113вҶ’        msg?.blocks
114вҶ’          .map((b) => ("text" in b ? b.text : b.type))
115вҶ’          .join(" ")
116вҶ’          .slice(0, 200) ?? messageId;
117вҶ’      setDeleteDialog({ messageId, isRound: true, preview });
118вҶ’    },
119вҶ’    [job.conversation?.messages],
120вҶ’  );
121вҶ’
122вҶ’  const handleConfirmDelete = useCallback(
123вҶ’    async (reason?: string) => {
124вҶ’      if (!deleteDialog) return;
125вҶ’      const { messageId, isRound } = deleteDialog;
126вҶ’      setDeleteDialog(null);
127вҶ’      if (isRound) {
128вҶ’        const result = await deletion.deleteRound(messageId, reason);
129вҶ’        deletionToast.showDeletedToast(messageId, true, result.length);
130вҶ’      } else {
131вҶ’        await deletion.deleteMessage(messageId, reason);
132вҶ’        deletionToast.showDeletedToast(messageId, false);
133вҶ’      }
134вҶ’    },
135вҶ’    [deleteDialog, deletion, deletionToast],
136вҶ’  );
137вҶ’
138вҶ’  const handleUndoDelete = useCallback(async () => {
139вҶ’    if (!deletionToast.toast) return;
140вҶ’    await deletion.restoreMessage(deletionToast.toast.messageId);
141вҶ’    deletionToast.dismissToast();
142вҶ’  }, [deletion, deletionToast]);
143вҶ’
144вҶ’  const mergedRef = useCallback(
145вҶ’    (node: HTMLElement | null) => {
146вҶ’      (
147вҶ’        session.sectionRef as React.MutableRefObject<HTMLElement | null>
148вҶ’      ).current = node;
149вҶ’      (
150вҶ’        popover.containerRef as React.MutableRefObject<HTMLElement | null>
151вҶ’      ).current = node;
152вҶ’    },
153вҶ’    [session.sectionRef, popover.containerRef],
154вҶ’  );
155вҶ’
156вҶ’  const artifact = view === "reader" ? "" : renderArtifact(view, job);
157вҶ’  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
158вҶ’  // `applyMarkdownRules` inklusive format_profile-Rules enthГӨlt. Der Server-
159вҶ’  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
160вҶ’  const displayedMarkdown = useMemo(() => {
161вҶ’    if (view !== "markdown") return artifact;
162вҶ’    try {
163вҶ’      return applyMarkdownRules(artifact, rules.activeRules);
164вҶ’    } catch {
165вҶ’      return artifact;
166вҶ’    }
167вҶ’  }, [artifact, rules.activeRules, view]);
168вҶ’
169вҶ’  const readerEffectsMap = useMemo(
170вҶ’    () =>
171вҶ’      view === "reader" && job.conversation
172вҶ’        ? buildReaderEffectsMap(rules.activeRules, job.conversation)
173вҶ’        : new Map(),
174вҶ’    [rules.activeRules, job.conversation, view],
175вҶ’  );
176вҶ’
177вҶ’  const handleDownloadMarkdown = useMemo(() => {
178вҶ’    if (view !== "markdown") return undefined;
179вҶ’    return () => {
180вҶ’      const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
181вҶ’      const url = URL.createObjectURL(blob);
182вҶ’      const a = document.createElement("a");
183вҶ’      a.href = url;
184вҶ’      a.download = `export-${job.id}.md`;
185вҶ’      document.body.appendChild(a);
186вҶ’      a.click();
187вҶ’      document.body.removeChild(a);
188вҶ’      setTimeout(() => URL.revokeObjectURL(url), 100);
189вҶ’    };
190вҶ’  }, [view, displayedMarkdown, job.id]);
191вҶ’  const showPopover =
192вҶ’    session.adjustModeEnabled &&
193вҶ’    Boolean(session.activeSelection) &&
194вҶ’    Boolean(session.activeAnchor);
195вҶ’
196вҶ’  const popoverCallbacksRef = useRef({
197вҶ’    handleDiscardSession: session.handleDiscardSession,
198вҶ’    activeSessionDetail: session.activeSessionDetail,
199вҶ’    handleRejectLastChange: rules.handleRejectLastChange,
200вҶ’    setReplyVisible: session.setReplyVisible,
201вҶ’  });
202вҶ’  popoverCallbacksRef.current = {
203вҶ’    handleDiscardSession: session.handleDiscardSession,
204вҶ’    activeSessionDetail: session.activeSessionDetail,
205вҶ’    handleRejectLastChange: rules.handleRejectLastChange,
206вҶ’    setReplyVisible: session.setReplyVisible,
207вҶ’  };
208вҶ’
209вҶ’  const handlePopoverClose = useCallback(() => {
210вҶ’    popoverCallbacksRef.current.handleDiscardSession();
211вҶ’  }, []);
212вҶ’
213вҶ’  const handleRejectLastChange = useCallback(() => {
214вҶ’    const {
215вҶ’      activeSessionDetail,
216вҶ’      handleRejectLastChange: reject,
217вҶ’      setReplyVisible,
218вҶ’    } = popoverCallbacksRef.current;
219вҶ’    if (activeSessionDetail) {
220вҶ’      void reject(activeSessionDetail).then((success) => {
221вҶ’        if (success) setReplyVisible(false);
222вҶ’      });
223вҶ’    }
224вҶ’  }, []);
225вҶ’
226вҶ’  const sessionError =
227вҶ’    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
228вҶ’
229вҶ’  const viewErrorFallback = (_error: Error, reset: () => void) => (
230вҶ’    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
231вҶ’      <p className="text-red-700">{miscLabels.viewLoadError}</p>
232вҶ’      <button
233вҶ’        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
234вҶ’        type="button"
235вҶ’        onClick={reset}
236вҶ’      >
237вҶ’        {miscLabels.retryButton}
238вҶ’      </button>
239вҶ’    </div>
240вҶ’  );
241вҶ’
242вҶ’  return (
243вҶ’    <section
244вҶ’      ref={mergedRef}
245вҶ’      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
246вҶ’    >
247вҶ’      <StatusHeader
248вҶ’        activeStage={activeStage}
249вҶ’        elapsedTime={elapsedTime}
250вҶ’        job={job}
251вҶ’      />
252вҶ’
253вҶ’      {job.warnings.length > 0 ? (
254вҶ’        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
255вҶ’          {job.warnings[0]}
256вҶ’        </div>
257вҶ’      ) : null}
258вҶ’
259вҶ’      {job.status === "failed" ? (
260вҶ’        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
261вҶ’          <p className="font-medium">{miscLabels.importFailed}</p>
262вҶ’          {job.errorStage && job.errorStage !== "done" && (
263вҶ’            <p className="text-sm mt-1">
264вҶ’              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
265вҶ’            </p>
266вҶ’          )}
267вҶ’          {job.error && <p className="text-sm mt-1">{job.error}</p>}
268вҶ’        </div>
269вҶ’      ) : job.status === "queued" || job.status === "running" ? (
270вҶ’        <LoadingStateBlock stageDetail={activeStage?.detail} />
271вҶ’      ) : (
272вҶ’        <div className="space-y-4">
273вҶ’          <CompletedToolbar
274вҶ’            adjustModeEnabled={session.adjustModeEnabled}
275вҶ’            isAdjustableView={isAdjustableView}
276вҶ’            rules={rules}
277вҶ’            view={view}
278вҶ’            onDownloadMarkdown={handleDownloadMarkdown}
279вҶ’            onToggleAdjustMode={session.toggleAdjustMode}
280вҶ’            onViewChange={onViewChange}
281вҶ’            deletionsCount={deletion.deletionsCount}
282вҶ’            showDeleted={deletion.showDeleted}
283вҶ’            onToggleShowDeleted={() =>
284вҶ’              deletion.setShowDeleted(!deletion.showDeleted)
285вҶ’            }
286вҶ’          />
287вҶ’
288вҶ’          {sessionError && !session.adjustModeEnabled ? (
289вҶ’            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
290вҶ’              {sessionError}
291вҶ’            </div>
292вҶ’          ) : null}
293вҶ’
294вҶ’          {view === "reader" ? (
295вҶ’            <ErrorBoundary fallback={viewErrorFallback}>
296вҶ’              <ReaderView
297вҶ’                activeRules={rules.activeRules}
298вҶ’                conversation={job.conversation}
299вҶ’                adjustModeEnabled={session.adjustModeEnabled}
300вҶ’                effectsMap={readerEffectsMap}
301вҶ’                highlightedRuleId={rules.hoveredRuleId}
302вҶ’                selectedBlock={
303вҶ’                  view === "reader" ? session.activeSelection : null
304вҶ’                }
305вҶ’                onSelectBlock={session.handleSelectionChange}
306вҶ’                deletedMessageIds={deletion.deletedMessageIds}
307вҶ’                showDeleted={deletion.showDeleted}
308вҶ’                onDeleteMessage={handleDeleteMessage}
309вҶ’                onDeleteRound={handleDeleteRound}
310вҶ’                onRestoreMessage={deletion.restoreMessage}
311вҶ’              />
312вҶ’            </ErrorBoundary>
313вҶ’          ) : view === "markdown" ? (
314вҶ’            <ErrorBoundary fallback={viewErrorFallback}>
315вҶ’              <MarkdownView
316вҶ’                activeRules={rules.activeRules}
317вҶ’                content={displayedMarkdown}
318вҶ’                adjustModeEnabled={session.adjustModeEnabled}
319вҶ’                highlightedRuleId={rules.hoveredRuleId}
320вҶ’                selectedRange={session.activeSelection}
321вҶ’                onSelectLines={session.handleSelectionChange}
322вҶ’              />
323вҶ’            </ErrorBoundary>
324вҶ’          ) : (
325вҶ’            <ErrorBoundary fallback={viewErrorFallback}>
326вҶ’              <ArtifactView content={artifact} />
327вҶ’            </ErrorBoundary>
328вҶ’          )}
329вҶ’
330вҶ’          {session.showGuide ? (
331вҶ’            <AdjustmentModeGuide
332вҶ’              view={view}
333вҶ’              onDismiss={() => session.setGuideDismissed(true)}
334вҶ’            />
335вҶ’          ) : null}
336вҶ’
337вҶ’          <ErrorBoundary
338вҶ’            fallback={
339вҶ’              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
340вҶ’                {miscLabels.adjustmentLoadError}
341вҶ’              </div>
342вҶ’            }
343вҶ’          >
344вҶ’            <AdjustmentPopover
345вҶ’              anchor={session.activeAnchor ?? null}
346вҶ’              containerRef={session.sectionRef}
347вҶ’              draftMessage={session.activeDraftMessage}
348вҶ’              error={session.activeSessionError}
349вҶ’              isLoading={session.activeSessionLoading || session.isDiscarding}
350вҶ’              isSubmitting={session.isSubmitting}
351вҶ’              open={
352вҶ’                showPopover &&
353вҶ’                Boolean(session.activeSelection) &&
354вҶ’                Boolean(session.activeAnchor)
355вҶ’              }
356вҶ’              sessionDetail={session.activeSessionDetail}
357вҶ’              showReply={session.replyVisible}
358вҶ’              view={view}
359вҶ’              onClose={handlePopoverClose}
360вҶ’              onDraftMessageChange={session.handleDraftMessageChange}
361вҶ’              onRejectLastChange={handleRejectLastChange}
362вҶ’              onSubmitMessage={session.handleSubmitMessage}
363вҶ’            />
364вҶ’          </ErrorBoundary>
365вҶ’        </div>
366вҶ’      )}
367вҶ’
368вҶ’      {deleteDialog && (
369вҶ’        <DeleteMessageDialog
370вҶ’          messagePreview={deleteDialog.preview}
