  1вҶ’import type { ConversationSnapshot } from "@chat-exporter/shared";
  2вҶ’import { eq } from "drizzle-orm";
  3вҶ’import { db, withTransaction } from "../db/client.js";
  4вҶ’import { conversationSnapshots } from "../db/schema.js";
  5вҶ’
  6вҶ’type SnapshotRow = typeof conversationSnapshots.$inferSelect;
  7вҶ’
  8вҶ’function toApiSnapshot(row: SnapshotRow): ConversationSnapshot {
  9вҶ’  return {
 10вҶ’    id: row.id,
 11вҶ’    importId: row.importId,
 12вҶ’    label: row.label,
 13вҶ’    isActive: row.isActive === 1,
 14вҶ’    createdAt: row.createdAt,
 15вҶ’    updatedAt: row.updatedAt,
 16вҶ’  };
 17вҶ’}
 18вҶ’
 19вҶ’export function createSnapshot(
 20вҶ’  importId: string,
 21вҶ’  label: string,
 22вҶ’): ConversationSnapshot {
 23вҶ’  const id = crypto.randomUUID();
 24вҶ’  const now = new Date().toISOString();
 25вҶ’
 26вҶ’  db.insert(conversationSnapshots)
 27вҶ’    .values({
 28вҶ’      id,
 29вҶ’      importId,
 30вҶ’      label,
 31вҶ’      isActive: 0,
 32вҶ’      createdAt: now,
 33вҶ’      updatedAt: now,
 34вҶ’    })
 35вҶ’    .run();
 36вҶ’
 37вҶ’  return {
 38вҶ’    id,
 39вҶ’    importId,
 40вҶ’    label,
 41вҶ’    isActive: false,
 42вҶ’    createdAt: now,
 43вҶ’    updatedAt: now,
 44вҶ’  };
 45вҶ’}
 46вҶ’
 47вҶ’export function listSnapshots(importId: string): ConversationSnapshot[] {
 48вҶ’  const rows = db
 49вҶ’    .select()
 50вҶ’    .from(conversationSnapshots)
 51вҶ’    .where(eq(conversationSnapshots.importId, importId))
 52вҶ’    .orderBy(conversationSnapshots.createdAt)
 53вҶ’    .all();
 54вҶ’
 55вҶ’  return rows.map(toApiSnapshot);
 56вҶ’}
 57вҶ’
 58вҶ’export function getActiveSnapshot(
 59вҶ’  importId: string,
 60вҶ’): ConversationSnapshot | null {
 61вҶ’  const row = db
 62вҶ’    .select()
 63вҶ’    .from(conversationSnapshots)
 64вҶ’    .where(eq(conversationSnapshots.importId, importId))
 65вҶ’    .all()
 66вҶ’    .find((r) => r.isActive === 1);
 67вҶ’
 68вҶ’  return row ? toApiSnapshot(row) : null;
 69вҶ’}
 70вҶ’
 71вҶ’export function activateSnapshot(snapshotId: string): ConversationSnapshot {
 72вҶ’  return withTransaction(() => {
 73вҶ’    const snapshot = db
 74вҶ’      .select()
 75вҶ’      .from(conversationSnapshots)
 76вҶ’      .where(eq(conversationSnapshots.id, snapshotId))
 77вҶ’      .get();
 78вҶ’
 79вҶ’    if (!snapshot) {
 80вҶ’      throw new Error(`Snapshot not found: ${snapshotId}`);
 81вҶ’    }
 82вҶ’
 83вҶ’    const now = new Date().toISOString();
 84вҶ’
 85вҶ’    // Deactivate all snapshots of the same import
 86вҶ’    db.update(conversationSnapshots)
 87вҶ’      .set({ isActive: 0, updatedAt: now })
 88вҶ’      .where(eq(conversationSnapshots.importId, snapshot.importId))
 89вҶ’      .run();
 90вҶ’
 91вҶ’    // Activate this snapshot
 92вҶ’    db.update(conversationSnapshots)
 93вҶ’      .set({ isActive: 1, updatedAt: now })
 94вҶ’      .where(eq(conversationSnapshots.id, snapshotId))
 95вҶ’      .run();
 96вҶ’
 97вҶ’    const updated = db
 98вҶ’      .select()
 99вҶ’      .from(conversationSnapshots)
100вҶ’      .where(eq(conversationSnapshots.id, snapshotId))
101вҶ’      .get();
102вҶ’
103вҶ’    if (!updated) {
104вҶ’      throw new Error(`Snapshot not found after activation: ${snapshotId}`);
105вҶ’    }
106вҶ’
107вҶ’    return toApiSnapshot(updated);
108вҶ’  });
109вҶ’}
110вҶ’
111вҶ’export function deactivateAllSnapshots(importId: string): void {
112вҶ’  withTransaction(() => {
113вҶ’    const now = new Date().toISOString();
114вҶ’    db.update(conversationSnapshots)
115вҶ’      .set({ isActive: 0, updatedAt: now })
116вҶ’      .where(eq(conversationSnapshots.importId, importId))
117вҶ’      .run();
118вҶ’  });
119вҶ’}
120вҶ’
121вҶ’export function deleteSnapshot(snapshotId: string): boolean {
122вҶ’  const result = db
123вҶ’    .delete(conversationSnapshots)
124вҶ’    .where(eq(conversationSnapshots.id, snapshotId))
125вҶ’    .run();
126вҶ’
127вҶ’  return result.changes > 0;
128вҶ’}
129вҶ’
130вҶ’export function renameSnapshot(
131вҶ’  snapshotId: string,
132вҶ’  label: string,
133вҶ’): ConversationSnapshot {
134вҶ’  const now = new Date().toISOString();
135вҶ’
136вҶ’  db.update(conversationSnapshots)
137вҶ’    .set({ label, updatedAt: now })
138вҶ’    .where(eq(conversationSnapshots.id, snapshotId))
139вҶ’    .run();
140вҶ’
141вҶ’  const updated = db
142вҶ’    .select()
143вҶ’    .from(conversationSnapshots)
144вҶ’    .where(eq(conversationSnapshots.id, snapshotId))
145вҶ’    .get();
146вҶ’
147вҶ’  if (!updated) {
148вҶ’    throw new Error(`Snapshot not found: ${snapshotId}`);
149вҶ’  }
150вҶ’
151вҶ’  return toApiSnapshot(updated);
152вҶ’}
