import type { Block, Message } from "@chat-exporter/shared";

import { copyMessageToClipboard } from "./message-clipboard";

// ---------------------------------------------------------------------------
// Mock navigator.clipboard
// ---------------------------------------------------------------------------

const mockWriteText = vi.fn().mockResolvedValue(undefined);
const mockWrite = vi.fn().mockResolvedValue(undefined);

beforeEach(() => {
  vi.clearAllMocks();
  Object.defineProperty(navigator, "clipboard", {
    value: { writeText: mockWriteText, write: mockWrite },
    writable: true,
    configurable: true,
  });
});

// ---------------------------------------------------------------------------
// Test helpers
// ---------------------------------------------------------------------------

function createMessage(overrides?: Partial<Message>): Message {
  return {
    id: "msg-1",
    role: "assistant",
    blocks: [
      { type: "paragraph", text: "Hello world" },
      { type: "heading", level: 2, text: "Section" },
    ],
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("copyMessageToClipboard", () => {
  describe("markdown format", () => {
    test("copies blocks as markdown text", async () => {
      const message = createMessage({
        blocks: [
          { type: "paragraph", text: "Hello world" },
          { type: "heading", level: 2, text: "Section" },
        ],
      });

      await copyMessageToClipboard(message, "markdown", message.blocks);

      expect(mockWriteText).toHaveBeenCalledTimes(1);
      const text = mockWriteText.mock.calls[0][0] as string;
      expect(text).toContain("Hello world");
      expect(text).toContain("## Section");
    });

    test("renders code blocks with language fence", async () => {
      const blocks: Block[] = [
        { type: "code", language: "typescript", text: "const x = 1;" },
      ];
      const message = createMessage({ blocks });

      await copyMessageToClipboard(message, "markdown", blocks);

      const text = mockWriteText.mock.calls[0][0] as string;
      expect(text).toContain("```typescript");
      expect(text).toContain("const x = 1;");
      expect(text).toContain("```");
    });

    test("renders list blocks", async () => {
      const blocks: Block[] = [
        { type: "list", ordered: false, items: ["Item A", "Item B"] },
      ];
      const message = createMessage({ blocks });

      await copyMessageToClipboard(message, "markdown", blocks);

      const text = mockWriteText.mock.calls[0][0] as string;
      expect(text).toContain("- Item A");
      expect(text).toContain("- Item B");
    });

    test("renders ordered list blocks", async () => {
      const blocks: Block[] = [
        { type: "list", ordered: true, items: ["First", "Second"] },
      ];
      const message = createMessage({ blocks });

      await copyMessageToClipboard(message, "markdown", blocks);

      const text = mockWriteText.mock.calls[0][0] as string;
      expect(text).toContain("1. First");
      expect(text).toContain("2. Second");
    });

    test("renders quote blocks", async () => {
      const blocks: Block[] = [{ type: "quote", text: "A wise saying" }];
      const message = createMessage({ blocks });

      await copyMessageToClipboard(message, "markdown", blocks);

      const text = mockWriteText.mock.calls[0][0] as string;
      expect(text).toContain("> A wise saying");
    });

    test("renders table blocks", async () => {
      const blocks: Block[] = [
        {
          type: "table",
          headers: ["Name", "Age"],
          rows: [["Alice", "30"]],
        },
      ];
      const message = createMessage({ blocks });

      await copyMessageToClipboard(message, "markdown", blocks);

      const text = mockWriteText.mock.calls[0][0] as string;
      expect(text).toContain("| Name | Age |");
      expect(text).toContain("| Alice | 30 |");
    });
  });

  describe("json format", () => {
    test("copies message as JSON string", async () => {
      const message = createMessage();

      await copyMessageToClipboard(message, "json", message.blocks);

      expect(mockWriteText).toHaveBeenCalledTimes(1);
      const text = mockWriteText.mock.calls[0][0] as string;
      const parsed = JSON.parse(text);
      expect(parsed.id).toBe("msg-1");
      expect(parsed.role).toBe("assistant");
      expect(parsed.blocks).toHaveLength(2);
    });
  });

  describe("handover format", () => {
    test("copies blocks as plain text for handover", async () => {
      const message = createMessage({
        blocks: [
          { type: "paragraph", text: "Summary here" },
          { type: "heading", level: 2, text: "Context" },
        ],
      });

      await copyMessageToClipboard(message, "handover", message.blocks);

      expect(mockWriteText).toHaveBeenCalledTimes(1);
      const text = mockWriteText.mock.calls[0][0] as string;
      expect(text).toContain("Summary here");
      expect(text).toContain("Context");
    });
  });

  describe("reader format", () => {
    test("copies blocks as HTML using clipboard.write", async () => {
      const blocks: Block[] = [
        { type: "paragraph", text: "Hello world" },
        { type: "heading", level: 2, text: "Section" },
      ];
      const message = createMessage({ blocks });

      await copyMessageToClipboard(message, "reader", blocks);

      expect(mockWrite).toHaveBeenCalledTimes(1);
      const clipboardItems = mockWrite.mock.calls[0][0] as ClipboardItem[];
      expect(clipboardItems).toHaveLength(1);

      const item = clipboardItems[0];
      const htmlBlob = await item.getType("text/html");
      const html = await htmlBlob.text();
      expect(html).toContain("<p");
      expect(html).toContain("Hello world");
      expect(html).toContain("<h2");
      expect(html).toContain("Section");
    });

    test("renders code blocks with pre/code tags", async () => {
      const blocks: Block[] = [
        { type: "code", language: "js", text: "const x = 1;" },
      ];
      const message = createMessage({ blocks });

      await copyMessageToClipboard(message, "reader", blocks);

      const clipboardItems = mockWrite.mock.calls[0][0] as ClipboardItem[];
      const item = clipboardItems[0];
      const htmlBlob = await item.getType("text/html");
      const html = await htmlBlob.text();
      expect(html).toContain("<pre");
      expect(html).toContain("<code");
      expect(html).toContain("const x = 1;");
    });
  });
});

import { renderHook } from "@testing-library/react";
import { describe, expect, test } from "vitest";

import type { Block, Conversation } from "@chat-exporter/shared";

import { useResolvedConversation } from "./use-resolved-conversation";

function createConversation(
  messages: Array<{ id: string; role: "user" | "assistant"; blocks: Block[] }>,
): Conversation {
  return {
    id: "conv-1",
    title: "Test Conversation",
    source: { url: "https://example.com/chat", platform: "chatgpt" },
    messages,
  };
}

function textBlock(text: string): Block {
  return { type: "paragraph", text };
}

describe("useResolvedConversation", () => {
  test("returns original messages when editedMessagesMap is empty", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
      { id: "m2", role: "assistant", blocks: [textBlock("Hi there")] },
    ]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, new Map()),
    );

    expect(result.current).toHaveLength(2);
    expect(result.current[0].blocks).toEqual([textBlock("Hello")]);
    expect(result.current[1].blocks).toEqual([textBlock("Hi there")]);
  });

  test("marks non-edited messages with isEdited: false", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
    ]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, new Map()),
    );

    expect(result.current[0].isEdited).toBe(false);
  });

  test("replaces blocks for edited messages", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Original")] },
      { id: "m2", role: "assistant", blocks: [textBlock("Original reply")] },
    ]);
    const editedBlocks: Block[] = [textBlock("Edited content")];
    const editsMap = new Map<string, Block[]>([["m1", editedBlocks]]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, editsMap),
    );

    expect(result.current[0].blocks).toEqual([textBlock("Edited content")]);
    expect(result.current[1].blocks).toEqual([textBlock("Original reply")]);
  });

  test("marks edited messages with isEdited: true", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Original")] },
      { id: "m2", role: "assistant", blocks: [textBlock("Reply")] },
    ]);
    const editsMap = new Map<string, Block[]>([
      ["m1", [textBlock("Edited")]],
    ]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, editsMap),
    );

    expect(result.current[0].isEdited).toBe(true);
    expect(result.current[1].isEdited).toBe(false);
  });

  test("handles undefined conversation gracefully", () => {
    const { result } = renderHook(() =>
      useResolvedConversation(undefined, new Map()),
    );

    expect(result.current).toEqual([]);
  });

  test("handles empty messages array", () => {
    const conversation = createConversation([]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, new Map()),
    );

    expect(result.current).toEqual([]);
  });

  test("preserves message id and role in resolved output", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
    ]);
    const editsMap = new Map<string, Block[]>([
      ["m1", [textBlock("Edited")]],
    ]);

    const { result } = renderHook(() =>
      useResolvedConversation(conversation, editsMap),
    );

    expect(result.current[0].id).toBe("m1");
    expect(result.current[0].role).toBe("user");
  });

  test("memoizes result when inputs do not change", () => {
    const conversation = createConversation([
      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
    ]);
    const editsMap = new Map<string, Block[]>();

    const { result, rerender } = renderHook(() =>
      useResolvedConversation(conversation, editsMap),
    );

    const firstResult = result.current;
    rerender();
    expect(result.current).toBe(firstResult);
  });
});

import { useMemo } from "react";

import type { Block, Conversation, Role } from "@chat-exporter/shared";

export type ResolvedMessage = {
  id: string;
  role: Role;
  blocks: Block[];
  isEdited: boolean;
};

export function useResolvedConversation(
  conversation: Conversation | undefined,
  editedMessagesMap: Map<string, Block[]>,
): ResolvedMessage[] {
  return useMemo(() => {
    if (!conversation) return [];

    return conversation.messages.map((message) => {
      const editedBlocks = editedMessagesMap.get(message.id);
      return {
        id: message.id,
        role: message.role,
        blocks: editedBlocks ?? message.blocks,
        isEdited: editedBlocks !== undefined,
      };
    });
  }, [conversation, editedMessagesMap]);
}

import { describe, expect, test } from "vitest";
import type { Block, Conversation } from "@chat-exporter/shared";
import {
  type MessageEditEntry,
  mergeEditsIntoConversation,
} from "./conversation-merge.js";

function createConversation(
  overrides: Partial<Conversation> = {},
): Conversation {
  return {
    id: "conv-1",
    title: "Test Conversation",
    source: { url: "https://chatgpt.com/share/abc", platform: "chatgpt" },
    messages: [
      {
        id: "msg-1",
        role: "user",
        blocks: [{ type: "paragraph", text: "Hello" }],
      },
      {
        id: "msg-2",
        role: "assistant",
        blocks: [
          { type: "paragraph", text: "Hi there" },
          { type: "code", language: "typescript", text: "const x = 1;" },
        ],
      },
      {
        id: "msg-3",
        role: "user",
        blocks: [{ type: "paragraph", text: "Thanks" }],
      },
    ],
    ...overrides,
  };
}

function createEditEntry(
  messageId: string,
  blocks: Block[],
  overrides: Partial<MessageEditEntry> = {},
): MessageEditEntry {
  return {
    messageId,
    editedBlocksJson: JSON.stringify(blocks),
    ...overrides,
  };
}

describe("mergeEditsIntoConversation", () => {
  test("returns original conversation unchanged when edits are empty", () => {
    const conversation = createConversation();

    const result = mergeEditsIntoConversation(conversation, []);

    expect(result).toBe(conversation);
  });

  test("replaces blocks for a matching message", () => {
    const conversation = createConversation();
    const newBlocks: Block[] = [
      { type: "paragraph", text: "Edited greeting" },
    ];
    const edits = [createEditEntry("msg-1", newBlocks)];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages[0].blocks).toEqual(newBlocks);
  });

  test("leaves non-matching messages unchanged", () => {
    const conversation = createConversation();
    const newBlocks: Block[] = [
      { type: "paragraph", text: "Edited greeting" },
    ];
    const edits = [createEditEntry("msg-1", newBlocks)];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages[1].blocks).toEqual(conversation.messages[1].blocks);
    expect(result.messages[2].blocks).toEqual(conversation.messages[2].blocks);
  });

  test("applies multiple edits to different messages", () => {
    const conversation = createConversation();
    const editedBlocks1: Block[] = [
      { type: "paragraph", text: "Edited user msg" },
    ];
    const editedBlocks2: Block[] = [
      { type: "heading", level: 2, text: "New heading" },
      { type: "paragraph", text: "Edited assistant response" },
    ];
    const edits = [
      createEditEntry("msg-1", editedBlocks1),
      createEditEntry("msg-2", editedBlocks2),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages[0].blocks).toEqual(editedBlocks1);
    expect(result.messages[1].blocks).toEqual(editedBlocks2);
    expect(result.messages[2].blocks).toEqual(conversation.messages[2].blocks);
  });

  test("does not mutate the original conversation", () => {
    const conversation = createConversation();
    const originalFirstBlocks = conversation.messages[0].blocks;
    const edits = [
      createEditEntry("msg-1", [{ type: "paragraph", text: "Changed" }]),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(conversation.messages[0].blocks).toBe(originalFirstBlocks);
    expect(result).not.toBe(conversation);
    expect(result.messages).not.toBe(conversation.messages);
  });

  test("preserves conversation metadata when edits are applied", () => {
    const conversation = createConversation();
    const edits = [
      createEditEntry("msg-1", [{ type: "paragraph", text: "Changed" }]),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.id).toBe(conversation.id);
    expect(result.title).toBe(conversation.title);
    expect(result.source).toBe(conversation.source);
  });

  test("ignores edits for non-existent message IDs", () => {
    const conversation = createConversation();
    const edits = [
      createEditEntry("non-existent-id", [
        { type: "paragraph", text: "Ghost edit" },
      ]),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages).toEqual(conversation.messages);
  });

  test("last edit wins when duplicate messageIds exist", () => {
    const conversation = createConversation();
    const edits = [
      createEditEntry("msg-1", [{ type: "paragraph", text: "First edit" }]),
      createEditEntry("msg-1", [{ type: "paragraph", text: "Second edit" }]),
    ];

    const result = mergeEditsIntoConversation(conversation, edits);

    expect(result.messages[0].blocks).toEqual([
      { type: "paragraph", text: "Second edit" },
    ]);
  });
});

