  describe("versions button visibility", () => {
    test("shows versions button when snapshotCount > 0", () => {
      renderToolbar({ snapshotCount: 3 });

      expect(screen.getByTestId("toolbar-versions")).toBeInTheDocument();
    });

    test("hides versions button when snapshotCount is 0", () => {
      renderToolbar({ snapshotCount: 0 });

      expect(
        screen.queryByTestId("toolbar-versions"),
      ).not.toBeInTheDocument();
    });

    test("hides versions button when snapshotCount is undefined", () => {
      renderToolbar({ snapshotCount: undefined });

      expect(
        screen.queryByTestId("toolbar-versions"),
      ).not.toBeInTheDocument();
    });
  });

  describe("exclusive toggle logic", () => {
    test("clicking edit button calls onEditModeChange with 'edit'", async () => {
      const user = userEvent.setup();
      const onEditModeChange = vi.fn();
      renderToolbar({ view: "reader", editMode: "view", onEditModeChange });

      await user.click(screen.getByTestId("toggle-edit-mode"));

      expect(onEditModeChange).toHaveBeenCalledWith("edit");
    });

    test("clicking active edit button calls onEditModeChange with 'view'", async () => {
      const user = userEvent.setup();
      const onEditModeChange = vi.fn();
      renderToolbar({ view: "reader", editMode: "edit", onEditModeChange });

      await user.click(screen.getByTestId("toggle-edit-mode"));

      expect(onEditModeChange).toHaveBeenCalledWith("view");
    });

    test("clicking adjust button when edit is active calls onToggleAdjustMode", async () => {
      const user = userEvent.setup();
      const { props } = renderToolbar({
        view: "reader",
        editMode: "edit",
        isAdjustableView: true,
      });

      const adjustButton = screen.getByTestId("toggle-adjust-mode-reader");
      await user.click(adjustButton);

      expect(props.onToggleAdjustMode).toHaveBeenCalled();
    });
  });

  describe("versions button", () => {
    test("calls onVersionsClick when clicked", async () => {
      const user = userEvent.setup();
      const onVersionsClick = vi.fn();
      renderToolbar({ snapshotCount: 2, onVersionsClick });

      await user.click(screen.getByTestId("toolbar-versions"));

      expect(onVersionsClick).toHaveBeenCalledTimes(1);
    });
  });
});

import type { ConversationSnapshot } from "@chat-exporter/shared";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useMemo } from "react";

import { orpc } from "@/lib/orpc";

export function useSnapshots(importId: string) {
  const queryClient = useQueryClient();

  const snapshotsQuery = useQuery({
    ...orpc.snapshots.list.queryOptions({ input: { importId } }),
  });

  const snapshots: ConversationSnapshot[] = snapshotsQuery.data ?? [];

  const activeSnapshot = useMemo(
    () => snapshots.find((s) => s.isActive) ?? null,
    [snapshots],
  );

  const invalidate = () =>
    queryClient.invalidateQueries({ queryKey: orpc.snapshots.list.key() });

  const createSnapshot = useMutation(
    orpc.snapshots.create.mutationOptions({
      onSuccess: () => invalidate(),
    }),
  );

  const activateSnapshot = useMutation(
    orpc.snapshots.activate.mutationOptions({
      onSuccess: () => invalidate(),
    }),
  );

  const deactivateSnapshot = useMutation(
    orpc.snapshots.deactivate.mutationOptions({
      onSuccess: () => invalidate(),
    }),
  );

  const deleteSnapshot = useMutation(
    orpc.snapshots.delete.mutationOptions({
      onSuccess: () => invalidate(),
    }),
  );

  const renameSnapshot = useMutation(
    orpc.snapshots.rename.mutationOptions({
      onSuccess: () => invalidate(),
    }),
  );

  return {
    snapshots,
    activeSnapshot,
    isLoading: snapshotsQuery.isLoading,
    create: (label: string) =>
      createSnapshot.mutateAsync({ importId, label }),
    activate: (snapshotId: string) =>
      activateSnapshot.mutateAsync({ snapshotId }),
    deactivate: () => deactivateSnapshot.mutateAsync({ importId }),
    delete: (snapshotId: string) =>
      deleteSnapshot.mutateAsync({ snapshotId }),
    rename: (snapshotId: string, label: string) =>
      renameSnapshot.mutateAsync({ snapshotId, label }),
    isCreating: createSnapshot.isPending,
    isActivating: activateSnapshot.isPending,
    isDeactivating: deactivateSnapshot.isPending,
    isDeleting: deleteSnapshot.isPending,
    isRenaming: renameSnapshot.isPending,
  };
}

import type { Block, Conversation } from "@chat-exporter/shared";

export interface MessageEditEntry {
  messageId: string;
  editedBlocksJson: string;
}

/**
 * Merges message edits into a conversation, returning a new Conversation
 * with edited blocks replacing the originals. Does not mutate the input.
 *
 * When duplicate messageIds exist in edits, the last entry wins.
 */
export function mergeEditsIntoConversation(
  conversation: Conversation,
  edits: MessageEditEntry[],
): Conversation {
  if (edits.length === 0) return conversation;

  const editMap = new Map<string, Block[]>();
  for (const edit of edits) {
    editMap.set(edit.messageId, JSON.parse(edit.editedBlocksJson));
  }

  return {
    ...conversation,
    messages: conversation.messages.map((msg) => {
      const editedBlocks = editMap.get(msg.id);
      if (editedBlocks) {
        return { ...msg, blocks: editedBlocks };
      }
      return msg;
    }),
  };
}

import type { Block } from "@chat-exporter/shared";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useCallback, useMemo, useRef } from "react";

import { orpc } from "@/lib/orpc";

const DEBOUNCE_MS = 500;

export function useMessageEdits(importId: string, snapshotId?: string) {
  const queryClient = useQueryClient();
  const debounceTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(
    new Map(),
  );

  const editsQuery = useQuery({
    ...orpc.edits.listForSnapshot.queryOptions({
      input: { snapshotId: snapshotId! },
    }),
    enabled: !!snapshotId,
  });

  const invalidate = () =>
    queryClient.invalidateQueries({
      queryKey: orpc.edits.listForSnapshot.key(),
    });

  const saveMutation = useMutation(
    orpc.edits.save.mutationOptions({
      onSuccess: () => invalidate(),
    }),
  );

  const deleteMutation = useMutation(
    orpc.edits.delete.mutationOptions({
      onSuccess: () => invalidate(),
    }),
  );

  const editedMessagesMap = useMemo(() => {
    const map = new Map<string, Block[]>();
    if (!editsQuery.data) return map;
    for (const edit of editsQuery.data) {
      map.set(edit.messageId, edit.editedBlocks);
    }
    return map;
  }, [editsQuery.data]);

  const saveEdit = useCallback(
    (messageId: string, blocks: Block[], annotation?: string) => {
      if (!snapshotId) return;

      const existing = debounceTimers.current.get(messageId);
      if (existing) clearTimeout(existing);

      const timer = setTimeout(() => {
        debounceTimers.current.delete(messageId);
        saveMutation.mutate({
          importId,
          snapshotId,
          messageId,
          editedBlocks: blocks,
          annotation,
        });
      }, DEBOUNCE_MS);

      debounceTimers.current.set(messageId, timer);
    },
    [importId, snapshotId, saveMutation.mutate],
  );

  const deleteEdit = useCallback(
    (messageId: string) => {
      if (!snapshotId) return;

      // Cancel any pending debounced save for this message
      const existing = debounceTimers.current.get(messageId);
      if (existing) {
        clearTimeout(existing);
        debounceTimers.current.delete(messageId);
      }

      return deleteMutation.mutateAsync({
        importId,
        snapshotId,
        messageId,
      });
    },
    [importId, snapshotId, deleteMutation.mutateAsync],
  );

  return {
    edits: editsQuery.data ?? [],
    editedMessagesMap,
    isLoading: editsQuery.isLoading,
    isSaving: saveMutation.isPending,
    isDeleting: deleteMutation.isPending,
    saveEdit,
    deleteEdit,
  };
}

